mapper.insert:
/** UsptEvlTrgetPresentnHistDao.insert */
insert into uspt_evl_trget_presentn_hist (
	   presentn_hist_id
	 , evl_trget_id
	 , presnatn_process_div_cd
	 , process_dt
	 , resn_cn
	 , creator_id
	 , created_dt
) values (
	   #{presentnHistId}
	 , #{evlTrgetId}
	 , #{presnatnProcessDivCd}
	 , clock_timestamp()
	 , #{resnCn}
	 , #{creatorId}
	 , clock_timestamp()
)

mapper.select:
/** UsptEvlTrgetPresentnHistDao.selectHistList */
select process_dt
	 , resn_cn
  from uspt_evl_trget_presentn_hist a
  	   inner join uspt_evl_trget b
  	   	 	   on b.evl_trget_id = a.evl_trget_id
	   inner join uspt_bsns_pblanc_applcnt c
	   		   on c.apply_id = b.apply_id
 where presentn_hist_id = #{presentnHistId}

   		and c.member_id = #{memberId}

/** UsptEvlTrgetPresentnHistDao.selectReason */
select to_char(process_dt,'yyyy-mm-dd hh24:mi')  as  st_process_dt
	    , resn_cn
  from uspt_evl_trget_presentn_hist a
 where a.evl_trget_id = #{evlTrgetId}
    and a.presnatn_process_div_cd =    'PRPR03'  /*보완요청*/
